const test = require("node:test");
const assert = require("node:assert");
const { roundHalfEven } = require("../src/round.js");

test("halves round to the nearest even integer (banker's rounding)", () => {
  assert.strictEqual(roundHalfEven(0.5), 0);
  assert.strictEqual(roundHalfEven(1.5), 2);
  assert.strictEqual(roundHalfEven(2.5), 2);
  assert.strictEqual(roundHalfEven(3.5), 4);
  assert.strictEqual(roundHalfEven(-0.5), 0);
  assert.strictEqual(roundHalfEven(-1.5), -2);
});

test("non-half values round normally", () => {
  assert.strictEqual(roundHalfEven(2.4), 2);
  assert.strictEqual(roundHalfEven(2.6), 3);
});
